with open ("memes-w5-all-2011-03-2012-02-n5000-call-nc10-cl2-cascades.txt", "r", encoding="utf-8") as f:
    lines = f.readlines()
    restlines = lines[5001:]
    results = []

    for line in tqdm(restlines, total= 27559944):
        items = line.strip().split(';')[1].split(',')
        dates = []
        markers = []

        for previous, current in zip(items[::2], items[1:][::2]):

            if float(current) < 262967:  # sanity check: dump dates before year 2000
                continue

            dates.append(float(current)*3600)
            markers.append(sorted_amount_ids[previous])

        if len(dates) > 32:
            dates = dates[:32] # Truncate to 32 events
            markers = markers[:32] # Truncate to 32 events

        if len(dates) < 2:
           continue

        df = pd.DataFrame({'unix': dates, 'type_event': markers})
        df['datetime'] = pd.to_datetime(df['unix'], unit='s')


        first_time = df['datetime'][0]
        df['time_since_start'] = (df['datetime'] - first_time).dt.total_seconds() / 3600
        df['time_since_last_event'] = (df['datetime'].diff().dt.total_seconds().fillna(0)) / 3600

        results.append([df['datetime'].to_list(), len(df), df['time_since_start'].to_list(),
                        df['time_since_last_event'].to_list(), df['type_event'].to_list()])

    gesamt_df = pd.DataFrame(results, columns=['datetime', 'seq_len', 'time_since_start', 'time_since_last_event', 'type_event'])

    gesamt_df.to_parquet('memetrack.parquet')


df = pd.read_parquet('memetrack.parquet')

df = df[[df['seq_len'] > 9]]

df['datetime'] = df['datetime'].swifter.apply(pd.to_datetime)
df['dim_process'] = 5000

print(len(df))
train = df.sample(frac=0.8, random_state=42)
train['seq_idx'] = range(len(train))
train.to_parquet('train.parquet', index=False)
remain = df.drop(train.index)
print(len(train), len(remain))
val = remain.sample(frac=0.5, random_state=42)
val['seq_idx'] = range(len(val))
test = remain.drop(val.index)
test['seq_idx'] = range(len(test))
val.to_parquet('validation.parquet', index=False)
test.to_parquet('test.parquet', index=False)
print(len(val), len(test))
